class Solution {
public:
    vector<int> arrayIndexSum(vector<int>& nums) {
        sort(nums.begin(), nums.end());
        int left = 0;
        int right = nums.size() - 1;
        while (left < right) {
            if (nums[left] + nums[right] < 0) {
                left++;
            } else if (nums[left] + nums[right] > 0) {
                right--;
            } else {
                return {nums[left], nums[right]};
            }
        }
        return {nums[left], nums[left]};
    }
};

